import{_ as t,o as e,c as i,ag as l}from"./chunks/framework.DXGyWiRo.js";const p="/media/202508/2025-08-07_112909_2827920.723732379847429.png",n="/media/202508/2025-08-07_113413_8921530.5140182470339252.png",o="/media/202508/2025-08-07_114228_0202270.31102384816038553.png",r="/media/202508/2025-08-07_165512_6493330.18533501431540667.png",u=JSON.parse('{"title":"基础配置","description":"","frontmatter":{"title":"基础配置"},"headers":[],"relativePath":"app-config/basic-config.md","filePath":"app-config/basic-config.md","lastUpdated":null}'),s={name:"app-config/basic-config.md"};function c(_,a,d,m,g,f){return e(),i("div",null,[...a[0]||(a[0]=[l('<p>基础配置概述</p><p>基础配置是AIUI极速超拟人交互类应用提供的配置项目，给开发者提供快速模块能力选型配置，包括：</p><h2 id="识别引擎" tabindex="-1">识别引擎 <a class="header-anchor" href="#识别引擎" aria-label="Permalink to &quot;识别引擎&quot;">​</a></h2><p>识别引擎主要是针对语音交互时音频转文字能力提供的服务配置项，开发者按需选择配置即可。</p><p><img src="'+p+'" alt="" title="null"></p><p>温馨提示</p><p>由于极速链路中针对识别引擎需要适配语义vad能力，客户如有非列表下其他识别引擎需求，可以反馈AIUI技术同事评估。</p><h2 id="选择模型" tabindex="-1">选择模型 <a class="header-anchor" href="#选择模型" aria-label="Permalink to &quot;选择模型&quot;">​</a></h2><p>这里可选择的模型指的是AIUI服务链路中最后的兜底回复模型，目前支持的有：</p><ul><li>讯飞星火交互大模型V2</li><li>讯飞星火儿童交互大模型</li><li>讯飞星火Spark4.0 Ultra</li><li>DeepSeek-V3</li><li>三方大模型 <ul><li>外部满足 openAi API协议的大模型可以按照通用协议进行配置，包含：<strong>接口地址、鉴权信息、模型标识</strong></li></ul></li></ul><p><img src="'+n+'" alt="" title="null"></p><p>AIUI官方提供的模型选配（交互大模型、儿童大模型、星火4.0 Ultra、deepseek-v3）调用授权（token和并发）都包含在AIUI极速应用授权中，开发者可以忽略。 三方大模型配置，是需要选择满足 openAi API协议的大模型进行配置，包含：<strong>接口地址、鉴权信息、模型标识</strong>三个信息。三方大模型配置后AIUI仅做托管调用，涉及的token或并发授权，需要开发者侧自行处理。 <a href="/app-config/third-party-llm.html" title="三方大模型配置">三方大模型配置</a>详见文档说明。</p><p><img src="'+o+'" alt="" title="null"></p><h2 id="回复角色" tabindex="-1">回复角色 <a class="header-anchor" href="#回复角色" aria-label="Permalink to &quot;回复角色&quot;">​</a></h2><p>回复角色是AIUI平台提供的大模型设备人设类方案，除了包含官方设置好的角色以外，也支持开发者自己定义角色回复。</p><p><img src="'+r+'" alt="" title="null"></p>',16)])])}const I=t(s,[["render",c]]);export{u as __pageData,I as default};
